{
  "summary": "This paper proposes vote-k, a novel unsupervised graph-based selective annotation method to reduce annotation costs for in-context learning with large language models. By selecting a small, diverse, and representative subset of unlabeled examples for annotation and combining this with similarity-based prompt retrieval, the method achieves significant performance gains across diverse NLP tasks and model sizes while substantially lowering annotation budgets.",
  "strengths": [
    {
      "point": "Effective annotation-efficient framework combining selective annotation and prompt retrieval",
      "evidence": "The two-step framework significantly improves in-context learning performance with only 18 or 100 annotated examples across 10 diverse NLP datasets."
    },
    {
      "point": "vote-k method balances representativeness and diversity in example selection",
      "evidence": "vote-k outperforms random selection, facility location, diversity-only, and least-confidence baselines, yielding up to 5.8% absolute gains with small annotation budgets."
    },
    {
      "point": "Comprehensive empirical evaluation across multiple LLM sizes and domain shifts",
      "evidence": "Experiments show consistent improvements from 2B to 175B parameter models and larger gains under domain mismatch conditions."
    },
    {
      "point": "Insights on differences between in-context learning and finetuning with selective annotation",
      "evidence": "Selective annotation benefits in-context learning but not finetuning, highlighting robustness to outliers and training instability in finetuning."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to established and recent active learning and exemplar selection methods",
      "evidence": "Only simple baselines like least-confidence sampling are included; no comparisons to core-set, BALD, gradient-based influence, or retrieval-augmented exemplar selection."
    },
    {
      "point": "Insufficient methodological details and reproducibility information",
      "evidence": "Missing explicit mathematical definitions of scoring functions, pseudocode for vote-k, specifics on Sentence-BERT variant, embedding processing, and confidence score computation."
    },
    {
      "point": "No quantitative ablation or sensitivity analysis for key hyperparameters",
      "evidence": "Parameters k=150 and ρ=10 are fixed without showing performance variation or robustness across datasets."
    },
    {
      "point": "Limited evaluation of annotation cost and human effort",
      "evidence": "No annotation time measurements, cost estimates, or human studies to substantiate claims of reduced annotation cost."
    },
    {
      "point": "Scalability and computational complexity not thoroughly analyzed",
      "evidence": "No runtime benchmarks, complexity analysis, or discussion of approximate nearest neighbor methods for large unlabeled pools."
    },
    {
      "point": "Limited exploration of prompt retrieval strategies and embedding choices",
      "evidence": "Only Sentence-BERT similarity retrieval is used; no experiments with alternative retrieval methods or embedding models."
    },
    {
      "point": "No qualitative or error analysis of selected examples",
      "evidence": "Lack of case studies or example-level insights into what vote-k prioritizes or misses."
    },
    {
      "point": "No discussion of robustness to annotation noise or label errors",
      "evidence": "Selective annotation methods can be sensitive to noisy labels, but this is not addressed."
    },
    {
      "point": "Limited generalizability analysis beyond NLP and small annotation budgets",
      "evidence": "No experiments on other modalities, larger annotation budgets, or multi-task/continual learning scenarios."
    }
  ],
  "questions": [
    {
      "question": "How does vote-k compare quantitatively to established active learning and recent exemplar selection methods?",
      "motivation": "Understanding relative advantages over strong baselines is critical to validate novelty and practical benefits."
    },
    {
      "question": "How sensitive is vote-k’s performance to hyperparameters k and ρ across different datasets and tasks?",
      "motivation": "Robustness and tuning guidelines are essential for practitioners to apply the method effectively."
    },
    {
      "question": "What is the precise method for computing LLM confidence scores and how does bucketing affect selection quality?",
      "motivation": "Confidence estimation impacts diversity and representativeness; clarity is needed for reproducibility and effectiveness."
    },
    {
      "question": "Can annotation cost reductions be validated with human studies measuring annotation time and effort?",
      "motivation": "Empirical cost savings beyond proxy metrics are necessary to confirm practical annotation efficiency."
    },
    {
      "question": "How does vote-k scale computationally with large unlabeled pools and can approximate methods maintain performance?",
      "motivation": "Scalability is crucial for real-world deployment on large datasets."
    },
    {
      "question": "What types of examples does vote-k select compared to baselines, and are there any biases introduced by embedding-based similarity?",
      "motivation": "Qualitative insights can reveal strengths, limitations, and fairness considerations."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
